  ],
  "explanations": [
    {
      "text": "In a normal German main clause, the conjugated verb comes in second position. This means it is the second sentence part, not always the second word. The first part can be the subject, a time phrase, or a place phrase.",
      "title": "Verb-second in German main clauses"
    },
    {
      "text": "If a time or place phrase comes first, the subject usually comes after the verb. English can say “Today Anna learns…,” but German uses the order “Heute lernt Anna…,” not “Heute Anna lernt…”.",
      "title": "Subject after the verb when something else comes first"
    }
  ],
  "questions": [
    {
      "answer": "lernt Anna",
      "distractors": [
        "Anna lernt",
        "lernen Anna",
        "Anna lernen"
      ],
